arguments.argument:
if global.gamePaused=false && gDeltaDoTicks
{
  if isCollisionWaterBottom(-4)
  {
    yVel-=0.2
    if yVel<-2
      yVel=-2
    else if yVel>2
      yVel=1
  }
  else
  {
    yVel+=0.2
    if yVel<-1
      yVel=-1
    else if yVel>10
      yVel=10
  }
  
  if isCollisionTop(1)
  {
    //if !collision_point(x,bbox_top-2,oPushRock,0,1)
    yVel=0
    
    if !isCollisionWaterBottom(-4)
      yVel+=0.5
  }
  if isCollisionBottom(1)
  {
    yVel=0
    if isCollisionWaterBottom(-4)
      yVel-=0.5
  }
}
